                      background: isSelected ? "#F0FDF4" : idx % 2 === 0 ? "#fff" : "#FAFAFA",
                      transition: "background 0.15s",
                      borderLeft: `3px solid ${emp.physicalGroup === "high" ? "#EF4444" : emp.physicalGroup === "medium" ? "#F59E0B" : "transparent"}`,
