                      {emp.alcohol !== "none"   && <span title="ดื่มแอลกอฮอล์" style={{ fontSize: 14 }}>🍺</span>}
                      {emp.substance !== "none" && <span title="สารเสพติด" style={{ fontSize: 14 }}>💊</span>}
